text:
{
  "formal_minutes": {
    "confirmed_decisions": [
      {
        "item": "공개 릴리스 목표는 금요일 15:00 KST로 한다.",
        "condition": "스모크 테스트가 통과할 경우"
      },
      {
        "item": "packageName 불일치가 발생하면 먼저 패키지 설정을 확인한다.",
        "condition": "스크립트 자체를 먼저 수정하지 않는다"
      },
      {
        "item": "Minjun이 스모크 테스트를 다시 실행하고 결과를 공유한다."
      },
      {
        "item": "Doyun이 실패 triage 메모를 `action_items.md`에 작성한다."
      },
      {
        "item": "Hara가 Minjun의 스모크 결과 게시 후 생성된 tarball 경로를 확인한다."
      }
    ],
    "rejected_proposals": [
      {
        "item": "smoke-theme-pack.mjs가 packageName 불일치를 무시하도록 바꾸자는 제안은 거절되었다."
      }
    ],
    "internal_stretch_goals": [
      {
        "item": "수요일 배포 제안은 내부 스트레치 목표로만 남겨두었다."
      },
      {
        "item": "README 설치 단계는 가능하면 목요일까지 검토하자는 언급이 있었지만, 공식 할당이나 확정은 없었다."
      }
    ],
    "non_decisions": [
      {
        "item": "README 설치 단계 검토의 담당자는 정해지지 않았다."
      },
      {
        "item": "Hara의 tarball 경로 확인에는 정확한 마감 시각이 정해지지 않았다."
      }
    ],
    "risks": [
      {
        "item": "tarball 경로가 잘못되면 릴리스가 지연될 수 있다."
      },
      {
        "item": "README 설치 단계가 오래되었으면 릴리스 노트가 사용자에게 잘못된 안내를 줄 수 있다."
      }
    ],
    "open_questions": [
      {
        "item": "최종 릴리스 승인 권한자가 누구인지 불명확하다."
      },
      {
        "item": "릴리스 노트에 내부 수요일 스트레치 목표를 언급해야 하는지 결정되지 않았다."
      }
    ]
  },
  "action_items": [
    {
      "owner": "Minjun",
      "task": "스모크 테스트를 다시 실행하고 결과를 공유한다.",
      "due": "금요일 10:00 KST",
      "status": "confirmed",
      "source_certainty": "confirmed"
    },
    {
      "owner": "Doyun",
      "task": "실패 triage 메모를 `action_items.md`에 작성한다.",
      "due": "금요일 12:00 KST",
      "status": "confirmed",
      "source_certainty": "confirmed"
    },
    {
      "owner": "Hara",
      "task": "Minjun이 스모크 결과를 게시한 뒤 생성된 tarball 경로를 확인한다.",
      "due": null,
      "status": "confirmed",
      "source_certainty": "confirmed"
    },
    {
      "owner": null,
      "task": "README 설치 단계 검토 여부를 조율한다.",
      "due": "목요일이면 좋다",
      "status": "unassigned",
      "source_certainty": "tentative"
    }
  ],
  "followup_note": "다음에는 스모크 테스트 통과 여부, tarball 경로, 최종 릴리스 승인권자, 그리고 릴리스 노트에 내부 수요일 스트레치 목표를 넣을지 여부를 확인하면 된다. 고객명, 외부 파트너명, 예산, 보안 이슈, 운영중단, 법무 승인, 소유자, 마감일은 이 회의 메모에 없는 한 절대 보충하거나 추정하지 말아야 한다.",
  "non_invention_rules": [
    "고객명 또는 외부 파트너명을 만들지 않는다.",
    "예산 정보를 추가하지 않는다.",
    "보안 사고, 운영중단, 법무 승인 요구를 추가하지 않는다.",
    "소유자나 최종 승인권자를 추정으로 채우지 않는다.",
    "명시되지 않은 마감일이나 시간을 창작하지 않는다.",
    "원문에 없는 결론을 확정으로 쓰지 않는다."
  ]
}
